scwin.login = $c.data.getMemInfo($p);
scwin.privAdmin = scwin.login.privAdmin;
scwin.sysAdminYn = scwin.login.sysAdminYn;
scwin.vUserHomeClsCd = scwin.login.userHomeClsCd;
scwin.vCoCd = scwin.login.coCd;
scwin.vLoginCoClsCd = scwin.login.coClsCd;
scwin.vAcctDeptCd = scwin.login.acctDeptCd;
scwin.appCheck = 0;
scwin.vCostClsCd = "";
scwin.vBizDomCd = "";
scwin.isSubCompany = false;
scwin.onpageload = function () {};
scwin.onUdcCompleted = async function () {
  btn_bSav1.hide("");
  var codeOptions = [{
    grpCd: "FI069",
    compID: "gr_prov:taxnCls"
  }];
  $c.data.setCommonCode($p, codeOptions);
  scwin.f_DelYn();
  var temp = "";
  acb_delYn.setSelectedIndex(0);
  ed_empNo.setValue(scwin.login.empNo);
  ed_empNm.setValue(scwin.login.userNm);
  ed_acctDeptCd.setValue(scwin.login.acctDeptCd);
  ed_acctDeptNm.setValue(scwin.login.deptNm);
  if ($c.gus.cfIsNull($p, scwin.login.occpgrdNm)) {
    scwin.login.occpgrdNm = "null";
  }
  ed_occpgrdNm.setValue(scwin.login.occpgrdNm);

  // 테스트용
  // ed_empNo.setValue("208004");
  // ed_empNo.setValue("051749");

  //디폴트 날짜 변경(1월1일 ~ 해당월말일까지)	
  let today = $c.date.getServerDateTime($p);
  let closeYm = today.substring(0, 6);
  let lastDD = $c.date.getLastDateOfMonth($p, closeYm);
  ed_approveDateTo.setValue(closeYm + lastDD);
  ed_approveDateFrom.setValue(closeYm + "01");
  $c.gus.cfDisableObjects($p, [ed_empNm, ed_occpgrdNm, ed_acctDeptNm]);
  if (scwin.isSubCompany) {
    temp = ed_approveDateFrom.getValue().trim() + ",,," + scwin.vCoCd;
  }
  rtnList = udc_srchAcctDeptCd.cfCommonPopUp(scwin.udc_srchAcctDeptCd_callBackFunc, scwin.vAcctDeptCd, '', 'T', null, null, null, null, temp, ",,,,,,1", "450", "500", null, null); // 귀속부서

  scwin.f_Retrieve();

  // cfCopyDataSetHeader(ds_card, ds_card_import);

  //사업부조회								
  sbm_cardNum.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC" + "&queryId=retrievecardNum&param1=" + ed_empNo.getValue() + "&param2=2";
  await $c.sbm.execute($p, sbm_cardNum);
};
scwin.udc_srchAcctDeptCd_callBackFunc = function (rtnList) {
  scwin.vCostClsCd = rtnList[9]; //비용구분코드
  scwin.vBizDomCd = rtnList[3]; //사업영역코드 (변동비 계정 조회안되도록 수정-06.12.22-박병길)
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
  if (!$c.gus.cfValidate($p, [ed_approveDateFrom, ed_approveDateTo, acb_delYn])) return true;

  // ds_search.UseChangeInfo = false;
  ed_approveDateFrom.setValue(ed_approveDateFrom.getValue().trim());
  ed_approveDateTo.setValue(ed_approveDateTo.getValue().trim());
  dma_search.set("occpgrdNm", ed_occpgrdNm.getValue());
  dma_search.set("empNm", ed_empNm.getValue());
  dma_search.set("empNo", ed_empNo.getValue());
  dma_search.set("acctDeptCd", ed_acctDeptCd.getValue());
  dma_search.set("acctDeptNm", ed_acctDeptNm.getValue());
  dma_search.set("delYn", acb_delYn.getValue());
  dma_search.set("cardNum", acb_cardNum.getValue());
  $c.sbm.execute($p, sbm_search);

  // em_cardNum.text = ds_card.NameValue(1,"cardNum");
  scwin.appCheck = 0;
};

//-------------------------------------------------------------------------
// 히든값체크
//-------------------------------------------------------------------------
scwin.f_HiddenCheck = async function (str, msg) {
  if (str.getValue().trim() == "") return true;
  if (str.getValue().trim() != str.options.hidVal) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_038, [msg]);
    str.focus();
    return false;
  } else {
    return true;
  }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  // 필수 입력 항목 중 빈 내용이 있다면
  //if (!cfCheckMandatory()) return;
  var i = 0;
  var count = 0;
  var slipCount = 0;
  var amt = 0; //매입금액
  var cancelAmt = 0; //매입취소금액
  var appNum = 0; //승인번호
  var gubun = 0; //구분 ( 03 - 매입, 04 - 매입취소 )
  var cancelAmt1 = 0; //이용금액 (매입취소처리 후)
  var cancelTex = 0; //부가세 (매입취소처리 후)
  var tax = 0; //세금
  var chkUseDt = "";
  var dtCnt = 0;

  // 그리드의 데이터 헤더를 발행팝업용 데이터셋에 복사한다. 

  // $c.gus.cfCopyDataSetHeader(ds_card, ds_card_import);
  var z = 0;

  // 조회결과 데이터셋의 루프만큼
  for (i = 0; i < ds_card.getTotalRow(); i++) {
    // 체크된 것만 로직을 타고, 
    if (ds_card.getCellData(i, "checkYn") == "T") {
      count = count + 1;
      // 행의 전표번호가 없다면 전표번호의 갯수를 1증가한다. 
      if (ds_card.getCellData(i, "slipNo") != "") {
        slipCount = slipCount + 1;
      }
      appNum = ds_card.getCellData(i, "approveNum"); // 승인번호 
      gubun = ds_card.getCellData(i, "gubun"); // 매출입구분코드 	        
      // 전체 조회된 데이터 중에 선택된 행과 같은 승인번호를 검색하여,
      // 취소 금액을 합산하여 준다. ( 이유!. 할인의 경우에는 같은 승인번호에 마이너스 금액으로 입력되기 때문에 합쳐서 생각해줄 필요가 있다.)
      for (j = 0; j <= ds_card.getTotalRow(); j++) {
        if (appNum == ds_card.getCellData(j, "approveNum") && gubun != ds_card.getCellData(j, "gubun")) {
          cancelAmt = cancelAmt + Number(ds_card.getCellData(j, "approveAmt"));
          cancelTex = cancelTex + Number(ds_card.getCellData(j, "tax"));
        }
      }
      ds_card_import.setCellData(z, "acctCd", ds_card.getCellData(i, "acctCd"));
      ds_card_import.setCellData(z, "acctNm", ds_card.getCellData(i, "acctNm"));
      ds_card_import.setCellData(z, "summary", ds_card.getCellData(i, "summary"));
      ds_card_import.setCellData(z, "summary", ds_card.getCellData(i, "summary"));

      // ds_card_import.ImportData(ds_card.ExportData(i, 1, true));
      ds_card_import.setRowData(ds_card_import.getTotalRow(), ds_card.getRowData(i));
      amt = ds_card_import.getCellData(z, "approveAmt"); // 사용금액
      tax = ds_card_import.getCellData(z, "tax"); // 부가세액

      if (tax == 0) {
        ds_card_import.setCellData(z, "approveAmt", amt + cancelAmt);
        ds_card_import.setCellData(z, "approveTotal", amt + cancelAmt);
      } else {
        ds_card_import.setCellData(z, "approveAmt", amt + cancelAmt);
        ds_card_import.setCellData(z, "tax", tax + cancelTex);
        ds_card_import.setCellData(z, "approveTotal", amt + tax + cancelAmt + cancelTex);
      }
      z++;
      cancelAmt = 0;
      cancelTex = 0;
      if (chkUseDt == "") {
        chkUseDt = ds_card.getCellData(i, "approveDate");
      }
      if (chkUseDt.substring(0, 6) != ds_card.getCellData(i, "approveDate").substring(0, 6)) {
        dtCnt += 1;
      }
    }
  }
  if (dtCnt > 0) {
    await $c.win.alert($p, "이용월이 다른건을 같이 처리할 수 없습니다.");
    return false;
  }
  if (count < 1) {
    await $c.win.alert($p, "선택한 데이타가 없습니다.");
    return false;
  } else {
    if (slipCount > 0) {
      await $c.win.alert($p, "이미 전표가 처리 된 데이타가 " + slipCount + "건 있습니다.");
      ds_card_import.removeAll();
      return false;
    }
  }

  // var style       = "center:yes; dialogwidth:840px; dialogheight:660px; scroll:yes; resizable:yes; status:yes;";
  // var strPath     = "fi_201_09_08p.jsp";
  // var returnValue = window.showModalDialog(strPath, ds_card_import ,style ) ;

  // var dc = ds_card_import.getAllArray();

  // let data = {
  // 	 card_import     : dc                             // getAllArray
  // }

  // let win_url = "/ui/ac/fi/gnrlaccount/slipmgnt/fi_201_09_08p.xml";    // fi_201_09_08p 미존재

  // let opts = {
  //       id        : "smpPop"
  //     , popupName : "부서배부"
  //     , modal     : true
  //     , type      : "browserPopup"
  //     , width     : 1180
  //     , height    : 600
  //     , title     : "부서배부"
  // };

  // let returnValue = await $c.win.openPopup(win_url, opts, data);

  ds_card_import.removeAll();
  scwin.f_Retrieve();
};

