scwin.f_Delete = async function () {
  if (ds_card.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_056, Array("데이타"));
    return;
  }

  // 이미 삭제된건 삭제하지 않는다.
  for (i = 0; i < ds_card.getTotalRow(); i++) {
    if (ds_card.getRowStatus(i) == "U" && ds_card.getCellData(i, "slipNo") != "") {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 데이타는 전표내역이 있어 삭제할 수 없습니다.");
      return;
    }
  }
  if ((await $c.win.confirm($p, "선택하신 데이타를 삭제하시겠습니까?")) == true) {
    sbm_delete.action = "/ac.fi.gnrlaccount.slipmgnt.DeleteCorporationCardAdjustContentsExcelCMD.do";
    $c.sbm.execute($p, sbm_delete);
  }
};

//-------------------------------------------------------------------------
// 삭제취소
