scwin.f_DeleteCancel = async function () {
  if (ds_card.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_056, Array("데이타"));
    return;
  }

  // 삭제된건만 삭제취소를 한다.
  for (i = 0; i < ds_card.getTotalRow(); i++) {
    if (ds_card.getRowStatus(i) == "U" && ds_card.getCellData(i, "delYn") == "0") {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 데이타는 삭제된 데이타가 아닙니다.");
      return;
    }
  }
  if ((await $c.win.confirm($p, "선택하신 데이타를 취소처리하시겠습니까?")) == true) {
    sbm_delete.action = "/ac.fi.gnrlaccount.slipmgnt.CancelDeleteCorporationCardAdjustContentsExcelCMD.do";
    $c.sbm.execute($p, sbm_delete);
  }
};
